/***********************************************
 * Compile Yesterday - MM Daily Monitoring
 * Input: raw campaign rows from Google Ads node
 * Output: { period:'yesterday', totals, by_channel, campaigns }
 ***********************************************/
const PERIOD = 'yesterday';
const rows = $input.all().map(i => i.json || {});

function toNum(v) {
  if (v == null) return 0;
  let s = String(v).replace(/[\u00A0€\s,]/g, '').trim();
  if (!s || s === '-') return 0;
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}
function normChannel(v) {
  const s = String(v || '').toUpperCase().replace(/[_\-\s]/g, ' ').trim();
  if (s.includes('SEARCH')) return 'SEARCH';
  if (s.includes('PERFORMANCE') || s.includes('PMAX') || s.includes('MAX')) return 'PERFORMANCE MAX';
  if (s.includes('DEMAND') || s.includes('DISCOVERY')) return 'DEMAND GEN';
  if (s.includes('DISPLAY')) return 'DISPLAY';
  if (s.includes('VIDEO')) return 'VIDEO';
  return s || 'OTHER';
}
const safeDiv = (n, d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n / d : 0;

// Aggregate by campaign
const byId = {};
for (const r of rows) {
  const id   = String(r['campaign.id']   || r.id   || r.campaign_id   || '').trim();
  const name = String(r['campaign.name'] || r.name || r.campaign_name || '').trim();
  const channel = normChannel(
    r['campaign.advertisingChannelType'] ||
    r['campaign.advertising_channel_type'] ||
    r.channel || r.campaign_type || ''
  );
  if (!id && !name) continue;
  const key = id || name;
  if (!byId[key]) byId[key] = { id, name, channel, imp:0, clk:0, cost:0, conv:0, val:0 };

  const imp  = toNum(r['metrics.impressions']  || r.imp  || r.impressions || 0);
  const clk  = toNum(r['metrics.clicks']       || r.clk  || r.clicks     || 0);
  const rawCost = toNum(r['metrics.costMicros'] || r['metrics.cost_micros'] || r.cost || r.spend || 0);
  const cost = rawCost > 10000 ? rawCost / 1e6 : rawCost; // micros → euros
  const conv = toNum(r['metrics.conversions']  || r.conv || r.conversions || 0);
  const rawVal = toNum(r['metrics.conversionsValue'] || r['metrics.conversions_value'] || r.val || r.conversion_value || 0);
  const val  = rawVal > 10000 ? rawVal / 1e6 : rawVal;

  byId[key].imp  += imp;
  byId[key].clk  += clk;
  byId[key].cost += cost;
  byId[key].conv += conv;
  byId[key].val  += val;
}

const campaigns = Object.values(byId).map(c => ({
  ...c,
  ctr:  safeDiv(c.clk,  c.imp),
  cpc:  safeDiv(c.cost, c.clk),
  cvr:  safeDiv(c.conv, c.clk),
  roas: safeDiv(c.val,  c.cost),
}));

const totals = { imp:0, clk:0, cost:0, conv:0, val:0 };
for (const c of campaigns) {
  totals.imp  += c.imp;
  totals.clk  += c.clk;
  totals.cost += c.cost;
  totals.conv += c.conv;
  totals.val  += c.val;
}
totals.ctr  = safeDiv(totals.clk,  totals.imp);
totals.cpc  = safeDiv(totals.cost, totals.clk);
totals.cvr  = safeDiv(totals.conv, totals.clk);
totals.roas = safeDiv(totals.val,  totals.cost);

const byChannel = {};
for (const c of campaigns) {
  const ch = c.channel || 'OTHER';
  if (!byChannel[ch]) byChannel[ch] = { imp:0, clk:0, cost:0, conv:0, val:0 };
  byChannel[ch].imp  += c.imp;
  byChannel[ch].clk  += c.clk;
  byChannel[ch].cost += c.cost;
  byChannel[ch].conv += c.conv;
  byChannel[ch].val  += c.val;
}
for (const b of Object.values(byChannel)) {
  b.ctr  = safeDiv(b.clk,  b.imp);
  b.cpc  = safeDiv(b.cost, b.clk);
  b.roas = safeDiv(b.val,  b.cost);
}

return [{ json: { period: PERIOD, totals, by_channel: byChannel, campaigns } }];

/***********************************************
 * Compile 7-day Average - MM Daily Monitoring
 * Aggregates last-7-days data and computes
 * rolling averages used as anomaly baseline.
 ***********************************************/
const PERIOD = 'last_7_days';
const rows = $input.all().map(i => i.json || {});

function toNum(v) {
  if (v == null) return 0;
  let s = String(v).replace(/[\u00A0€\s,]/g, '').trim();
  if (!s || s === '-') return 0;
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}
function normChannel(v) {
  const s = String(v || '').toUpperCase().replace(/[_\-\s]/g, ' ').trim();
  if (s.includes('SEARCH')) return 'SEARCH';
  if (s.includes('PERFORMANCE') || s.includes('PMAX') || s.includes('MAX')) return 'PERFORMANCE MAX';
  if (s.includes('DEMAND') || s.includes('DISCOVERY')) return 'DEMAND GEN';
  return s || 'OTHER';
}
const safeDiv = (n, d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n / d : 0;

const byId = {};
for (const r of rows) {
  const id   = String(r['campaign.id']   || r.id   || r.campaign_id   || '').trim();
  const name = String(r['campaign.name'] || r.name || r.campaign_name || '').trim();
  const channel = normChannel(
    r['campaign.advertisingChannelType'] ||
    r['campaign.advertising_channel_type'] ||
    r.channel || r.campaign_type || ''
  );
  if (!id && !name) continue;
  const key = id || name;
  if (!byId[key]) byId[key] = { id, name, channel, imp:0, clk:0, cost:0, conv:0, val:0 };

  const imp  = toNum(r['metrics.impressions']  || r.imp  || r.impressions || 0);
  const clk  = toNum(r['metrics.clicks']       || r.clk  || r.clicks     || 0);
  const rawCost = toNum(r['metrics.costMicros'] || r['metrics.cost_micros'] || r.cost || r.spend || 0);
  const cost = rawCost > 10000 ? rawCost / 1e6 : rawCost;
  const conv = toNum(r['metrics.conversions']  || r.conv || r.conversions || 0);
  const rawVal = toNum(r['metrics.conversionsValue'] || r['metrics.conversions_value'] || r.val || r.conversion_value || 0);
  const val  = rawVal > 10000 ? rawVal / 1e6 : rawVal;

  byId[key].imp  += imp;
  byId[key].clk  += clk;
  byId[key].cost += cost;
  byId[key].conv += conv;
  byId[key].val  += val;
}

const DAYS = 7;
const campaigns = Object.values(byId).map(c => ({
  ...c,
  // Rolling averages: CPC and CTR are ratio-based (same calculation)
  ctr:  safeDiv(c.clk,  c.imp),
  cpc:  safeDiv(c.cost, c.clk),
  cvr:  safeDiv(c.conv, c.clk),
  roas: safeDiv(c.val,  c.cost),
  // Daily averages (used for spend pacing)
  daily_cost: c.cost / DAYS,
  daily_clk:  c.clk  / DAYS,
  daily_conv: c.conv / DAYS,
}));

const totals = { imp:0, clk:0, cost:0, conv:0, val:0 };
for (const c of campaigns) {
  totals.imp  += c.imp;
  totals.clk  += c.clk;
  totals.cost += c.cost;
  totals.conv += c.conv;
  totals.val  += c.val;
}
totals.ctr         = safeDiv(totals.clk,  totals.imp);
totals.cpc         = safeDiv(totals.cost, totals.clk);
totals.roas        = safeDiv(totals.val,  totals.cost);
totals.daily_cost  = totals.cost / DAYS;
totals.daily_clk   = totals.clk  / DAYS;
totals.daily_conv  = totals.conv / DAYS;

const byChannel = {};
for (const c of campaigns) {
  const ch = c.channel || 'OTHER';
  if (!byChannel[ch]) byChannel[ch] = { imp:0, clk:0, cost:0, conv:0, val:0 };
  byChannel[ch].imp  += c.imp;
  byChannel[ch].clk  += c.clk;
  byChannel[ch].cost += c.cost;
  byChannel[ch].conv += c.conv;
  byChannel[ch].val  += c.val;
}
for (const b of Object.values(byChannel)) {
  b.ctr  = safeDiv(b.clk,  b.imp);
  b.cpc  = safeDiv(b.cost, b.clk);
  b.roas = safeDiv(b.val,  b.cost);
}

return [{ json: { period: PERIOD, totals, by_channel: byChannel, campaigns } }];

/***********************************************
 * Detect Anomalies + Prep Daily Payload
 * Thresholds: CPC up >25%, CTR down >20%
 * Also flags per-campaign anomalies (≥€20 spend)
 ***********************************************/
const items = $input.all().map(i => i.json);
const yesterday = items.find(i => i.period === 'yesterday');
const avg7d     = items.find(i => i.period === 'last_7_days');

if (!yesterday || !avg7d) {
  throw new Error(`Missing data — got periods: ${items.map(i=>i.period).join(', ')}`);
}

const safeDiv = (n, d) => (d && Number.isFinite(n) && Number.isFinite(d)) ? n / d : 0;
const pctChange = (current, baseline) =>
  (baseline > 0) ? (current - baseline) / baseline : null;

const CPC_SPIKE   = 0.25;   // +25%
const CTR_DROP    = -0.20;  // -20%
const ROAS_DROP   = -0.30;  // -30%
const MIN_SPEND   = 20;     // min €20 spend to flag per-campaign
const anomalies   = [];

// ── Overall CPC ──
const cpcDelta = pctChange(yesterday.totals.cpc, avg7d.totals.cpc);
if (cpcDelta !== null && cpcDelta > CPC_SPIKE) {
  anomalies.push({
    type: 'CPC_HIGH', severity: cpcDelta > 0.5 ? 'critical' : 'warning',
    scope: 'overall', metric: 'CPC',
    yesterday: yesterday.totals.cpc, baseline: avg7d.totals.cpc,
    change_pct: cpcDelta,
    message: `Overall CPC up ${(cpcDelta*100).toFixed(1)}% vs 7-day avg (€${yesterday.totals.cpc.toFixed(2)} vs €${avg7d.totals.cpc.toFixed(2)})`,
  });
}

// ── Overall CTR ──
const ctrDelta = pctChange(yesterday.totals.ctr, avg7d.totals.ctr);
if (ctrDelta !== null && ctrDelta < CTR_DROP) {
  anomalies.push({
    type: 'CTR_LOW', severity: ctrDelta < -0.40 ? 'critical' : 'warning',
    scope: 'overall', metric: 'CTR',
    yesterday: yesterday.totals.ctr, baseline: avg7d.totals.ctr,
    change_pct: ctrDelta,
    message: `Overall CTR down ${(Math.abs(ctrDelta)*100).toFixed(1)}% vs 7-day avg`,
  });
}

// ── Overall ROAS ──
const roasDelta = pctChange(yesterday.totals.roas, avg7d.totals.roas);
if (roasDelta !== null && roasDelta < ROAS_DROP && yesterday.totals.conv > 0) {
  anomalies.push({
    type: 'ROAS_DROP', severity: roasDelta < -0.50 ? 'critical' : 'warning',
    scope: 'overall', metric: 'ROAS',
    yesterday: yesterday.totals.roas, baseline: avg7d.totals.roas,
    change_pct: roasDelta,
    message: `Overall campaign efficiency down ${(Math.abs(roasDelta)*100).toFixed(1)}% vs 7-day avg`,
  });
}

// ── Per-campaign anomalies ──
for (const camp of yesterday.campaigns || []) {
  if (camp.cost < MIN_SPEND) continue;
  const camp7d = (avg7d.campaigns || []).find(c =>
    (c.id && c.id === camp.id) || (c.name && c.name === camp.name)
  );
  if (!camp7d) continue;

  const campCpcDelta = pctChange(camp.cpc, camp7d.cpc);
  const campCtrDelta = pctChange(camp.ctr, camp7d.ctr);

  if (campCpcDelta !== null && campCpcDelta > CPC_SPIKE) {
    anomalies.push({
      type: 'CAMPAIGN_CPC_HIGH', severity: 'warning',
      scope: 'campaign', campaign: camp.name, metric: 'CPC',
      change_pct: campCpcDelta,
      message: `"${camp.name}": CPC up ${(campCpcDelta*100).toFixed(1)}% (€${camp.cpc.toFixed(2)} vs €${camp7d.cpc.toFixed(2)})`,
    });
  }
  if (campCtrDelta !== null && campCtrDelta < CTR_DROP) {
    anomalies.push({
      type: 'CAMPAIGN_CTR_LOW', severity: 'warning',
      scope: 'campaign', campaign: camp.name, metric: 'CTR',
      change_pct: campCtrDelta,
      message: `"${camp.name}": CTR down ${(Math.abs(campCtrDelta)*100).toFixed(1)}%`,
    });
  }
}

// ── Spend pacing ──
if (yesterday.totals.cost > avg7d.totals.daily_cost * 1.5) {
  anomalies.push({
    type: 'SPEND_SPIKE', severity: 'warning',
    scope: 'overall', metric: 'Spend',
    yesterday: yesterday.totals.cost, baseline: avg7d.totals.daily_cost,
    change_pct: pctChange(yesterday.totals.cost, avg7d.totals.daily_cost),
    message: `Daily spend €${yesterday.totals.cost.toFixed(2)} is ${((yesterday.totals.cost/avg7d.totals.daily_cost - 1)*100).toFixed(0)}% above 7-day daily avg`,
  });
}

const date = new Date();
date.setDate(date.getDate() - 1);
const dateStr = date.toISOString().split('T')[0];

return [{
  json: {
    brand: 'MM',
    date: dateStr,
    yesterday,
    rolling_7d: avg7d,
    anomalies,
    has_anomalies: anomalies.length > 0,
    has_critical: anomalies.some(a => a.severity === 'critical'),
    anomaly_count: anomalies.length,
  }
}];

/******************************************************
 * Google Ads → Compile Results (Weekly v4.5w)
 * - Same logic as monthly v4.5, adapted for weekly periods
 * - Ignores Date columns (groups all rows by campaign)
 * - Computes ROAS = conv_value / cost
 * - Rounds conversions (display) to ≤2 decimals
 * - Formats Top/Bottom 3 labels cleanly
 ******************************************************/
const BRAND  = 'MM';          // ← 'MT' or 'MM'
const PERIOD = 'last_week';   // ← 'last_week' or 'prev_week'
const MIN_SPEND_FOR_RANK = 50; // a bit lower for weekly
const MIN_NAME_LEN = 2;
const DEBUG = false;

const rows = $input.all().map(i => i.json || {});
const up = s => (s ?? '').toString().trim().toUpperCase();

// ---------- helpers ----------
function toNum(v) {
  if (v === null || v === undefined) return 0;
  let s = String(v).replace(/\u00A0/g,' ').replace(/[€\s]/g,'').trim();
  if (!s || s === '-') return 0;
  const hasDot = s.includes('.'), hasCom = s.includes(',');
  if (hasDot && hasCom) {
    // handle "12.345,67" vs "12,345.67"
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g,'').replace(',', '.');
    else s = s.replace(/,/g,'');
  } else if (hasCom && !hasDot) {
    const parts = s.split(',');
    s = (parts[parts.length-1].length <= 2) ? (parts.slice(0,-1).join('') + '.' + parts.at(-1)) : s.replace(/,/g,'');
  } else s = s.replace(/,/g,'');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}
function toPct(v){
  if (v === null || v === undefined) return 0;
  let s = String(v).trim();
  const pct = s.endsWith('%');
  s = s.replace('%','');
  const n = toNum(s);
  return pct ? n/100 : (n>1 ? n/100 : n);
}
function normKey(k){ return String(k).toLowerCase().replace(/[\s\.\(\)\-_/\\]/g,''); }

// format conversions nicely (≤2 decimals)
function fmtConv(n) {
  if (!Number.isFinite(n)) return '0';
  const rounded = Math.round(n);
  return Math.abs(n - rounded) < 1e-9 ? String(rounded) : n.toFixed(2);
}

// fuzzy getter (handles 'clk', 'clicks', localized headers, etc.)
function getFuzzy(r, preds) {
  const entries = Object.keys(r).map(k => ({ k, nk: normKey(k) }));
  for (const {k,nk} of entries) {
    for (const p of preds) {
      if (typeof p === 'function' && p(nk)) return { key:k, value:r[k] };
      if (p instanceof RegExp && p.test(nk)) return { key:k, value:r[k] };
    }
  }
  return { key:null, value:undefined };
}

// pickers
function pickCost(r){ return getFuzzy(r,[ nk => nk==='cost' || nk==='spend' || nk.endsWith('costeur') || nk==='kosten' ]); }
function pickClicks(r){ return getFuzzy(r,[ nk => nk.includes('click') || nk==='clk' || nk==='klicks' ]); }
function pickImps(r){ return getFuzzy(r,[ nk => nk.includes('impression') || nk==='imp' || nk==='einblendungen' ]); }
function pickConv(r){ return getFuzzy(r,[ nk => nk.includes('allconv') || (nk.includes('conv') && !nk.includes('value')) || nk==='conversions' ]); }
function pickConvValue(r){ return getFuzzy(r,[ nk => nk==='convvalue' || nk.includes('conversionvalue') || nk.includes('allconvvalue') || nk.includes('conv_value') || nk.includes('revenue') || nk.includes('umsatz') ]); }
function pickROAS(r){ return getFuzzy(r,[ nk => nk==='roas' || nk.includes('returnonadspend') ]); }
function pickValuePerCost(r){ return getFuzzy(r,[ nk => nk.includes('valuepercost') || nk.includes('convvaluepercost') ]); }

const normalizeChannel = (c) => {
  const x = up(c);
  if (x.includes('SEARCH')) return 'SEARCH';
  if (x.includes('PERFORMANCE') || x.includes('P-MAX') || x.includes('PMAX')) return 'PERFORMANCE MAX';
  if (x.includes('DEMAND') || x.includes('DISCOVERY') || x.includes('VIDEO') || x.includes('DISPLAY') || x.includes('YOUTUBE'))
    return 'DEMAND GEN';
  return x || 'UNKNOWN';
};

// ---------- main mapping ----------
function mapRow(r){
  const name =
    (r.name ?? r.campaign_name ?? r['Campaign'] ?? r['Kampagne'] ?? r['campaign'] ?? r.id ?? '').toString().trim() || `Unknown_${r.id ?? ''}`;
  const channel = normalizeChannel(r.channel ?? r.campaign_type ?? r['Channel'] ?? r['Netzwerk'] ?? '');

  const costK = pickCost(r), clicksK = pickClicks(r), impsK = pickImps(r);
  const convK = pickConv(r), valK = pickConvValue(r);
  const roasK = pickROAS(r), vpcK = pickValuePerCost(r);

  const cost = toNum(costK.value);
  const clk  = toNum(clicksK.value);
  const imp  = toNum(impsK.value);
  const conv = toNum(convK.value);
  let val    = toNum(valK.value);

  const roasFromCol = toNum(roasK.value);
  const roasFromVpc = toNum(vpcK.value);
  if (val === 0 && roasFromCol > 0 && cost > 0) val = roasFromCol * cost;
  else if (val === 0 && roasFromVpc > 0 && cost > 0) val = roasFromVpc * cost;

  const roas = (cost > 0 && val > 0) ? (val / cost) : 0;
  const ctr  = imp>0 ? (clk/imp) : toPct(r.ctr ?? r['CTR']);
  const cpc  = clk>0 ? (cost/clk) : toNum(r.cpc ?? r['CPC']);
  const cvr  = clk>0 ? (conv/clk) : toPct(r.cvr ?? r['CVR'] ?? r['Conv rate']);

  if (DEBUG) console.log('Mapped', name, { cost, val, conv, roas });

  return { name, channel, imp, clk, cost, conv, val, ctr, cpc, cvr, roas };
}

// ---------- group by campaign ----------
const mapped = rows.map(mapRow).filter(d => d.name && d.name.length >= MIN_NAME_LEN);
const grouped = {};
for (const r of mapped) {
  const k = r.name;
  if (!grouped[k]) grouped[k] = { ...r };
  else {
    const g = grouped[k];
    g.imp += r.imp; g.clk += r.clk; g.cost += r.cost; g.conv += r.conv; g.val += r.val;
    g.ctr = g.imp>0 ? (g.clk/g.imp) : 0;
    g.cpc = g.clk>0 ? (g.cost/g.clk) : 0;
    g.cvr = g.clk>0 ? (g.conv/g.clk) : 0;
    g.roas = g.cost>0 ? (g.val/g.cost) : 0;
  }
}
const data = Object.values(grouped);

// ---------- totals ----------
const sum = (arr,k)=>arr.reduce((a,r)=>a+(r[k]||0),0);
const totals = {
  spend: sum(data,'cost'),
  value: sum(data,'val'),
  conv:  sum(data,'conv'),
  clicks: sum(data,'clk'),
  impressions: sum(data,'imp'),
};
totals.roas = totals.spend>0 ? (totals.value/totals.spend) : 0;

// ---------- per-channel ----------
const by_channel = {};
for (const r of data) {
  const ch = r.channel || 'UNKNOWN';
  if (!by_channel[ch]) by_channel[ch] = { spend:0, value:0, conv:0, clicks:0, impressions:0 };
  const g = by_channel[ch];
  g.spend += r.cost; g.value += r.val; g.conv += r.conv; g.clicks += r.clk; g.impressions += r.imp;
}
for (const ch of Object.keys(by_channel)) {
  const g = by_channel[ch];
  g.roas = g.spend>0 ? (g.value/g.spend) : 0;
  g.ctr  = g.impressions>0 ? (g.clicks/g.impressions) : 0;
  g.cpc  = g.clicks>0 ? (g.spend/g.clicks) : 0;
}
const channel_split = {};
for (const ch of Object.keys(by_channel)) {
  channel_split[ch] = totals.spend>0 ? (by_channel[ch].spend/totals.spend) : 0;
}

// ---------- highs & lows ----------
const eligible = data.filter(r => r.cost >= MIN_SPEND_FOR_RANK).sort((a,b)=>b.roas-a.roas);
function toEntry(r){
  const cvrPct = r.clk>0 ? (r.conv/r.clk)*100 : (r.cvr*100);
  const ctrPct = r.imp>0 ? (r.clk/r.imp)*100 : (r.ctr*100);
  return {
    name:r.name,
    roas:r.roas,
    conv:r.conv,
    conv_display: fmtConv(r.conv),
    cvr_pct:cvrPct||0,
    spend:r.cost,
    clicks:r.clk,
    ctr_pct:ctrPct||0,
    cpc:r.cpc
  };
}
const topRaw = eligible.slice(0,3).map(toEntry);
const bottomRaw = eligible.length>=6 ? eligible.slice().sort((a,b)=>a.roas-b.roas).slice(0,3).map(toEntry) : [];

// formatted label
const label = e => `${e.name} (ROAS ${e.roas.toFixed(2)}, CVR ${e.cvr_pct.toFixed(2)}%, ${fmtConv(e.conv)} conv)`;

const highs_lows = {
  top3_labels: topRaw.map(label),
  bottom3_labels: bottomRaw.map(label),
  top3_raw: topRaw,
  bottom3_raw: bottomRaw
};

// ---------- output ----------
const out = {
  brand: BRAND,
  period: PERIOD,
  totals,
  by_channel,
  channel_split,
  highs_lows,
  source_rows: rows.length,
  grouped_rows: data.length
};
return [{ json: out }];

/******************************************************
 * Google Ads → Compile Results (Weekly v4.5w)
 * - Same logic as monthly v4.5, adapted for weekly periods
 * - Ignores Date columns (groups all rows by campaign)
 * - Computes ROAS = conv_value / cost
 * - Rounds conversions (display) to ≤2 decimals
 * - Formats Top/Bottom 3 labels cleanly
 ******************************************************/
const BRAND  = 'MM';          // ← 'MT' or 'MM'
const PERIOD = 'prev_week';   // ← 'last_week' or 'prev_week'
const MIN_SPEND_FOR_RANK = 50; // a bit lower for weekly
const MIN_NAME_LEN = 2;
const DEBUG = false;

const rows = $input.all().map(i => i.json || {});
const up = s => (s ?? '').toString().trim().toUpperCase();

// ---------- helpers ----------
function toNum(v) {
  if (v === null || v === undefined) return 0;
  let s = String(v).replace(/\u00A0/g,' ').replace(/[€\s]/g,'').trim();
  if (!s || s === '-') return 0;
  const hasDot = s.includes('.'), hasCom = s.includes(',');
  if (hasDot && hasCom) {
    // handle "12.345,67" vs "12,345.67"
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g,'').replace(',', '.');
    else s = s.replace(/,/g,'');
  } else if (hasCom && !hasDot) {
    const parts = s.split(',');
    s = (parts[parts.length-1].length <= 2) ? (parts.slice(0,-1).join('') + '.' + parts.at(-1)) : s.replace(/,/g,'');
  } else s = s.replace(/,/g,'');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
}
function toPct(v){
  if (v === null || v === undefined) return 0;
  let s = String(v).trim();
  const pct = s.endsWith('%');
  s = s.replace('%','');
  const n = toNum(s);
  return pct ? n/100 : (n>1 ? n/100 : n);
}
function normKey(k){ return String(k).toLowerCase().replace(/[\s\.\(\)\-_/\\]/g,''); }

// format conversions nicely (≤2 decimals)
function fmtConv(n) {
  if (!Number.isFinite(n)) return '0';
  const rounded = Math.round(n);
  return Math.abs(n - rounded) < 1e-9 ? String(rounded) : n.toFixed(2);
}

// fuzzy getter (handles 'clk', 'clicks', localized headers, etc.)
function getFuzzy(r, preds) {
  const entries = Object.keys(r).map(k => ({ k, nk: normKey(k) }));
  for (const {k,nk} of entries) {
    for (const p of preds) {
      if (typeof p === 'function' && p(nk)) return { key:k, value:r[k] };
      if (p instanceof RegExp && p.test(nk)) return { key:k, value:r[k] };
    }
  }
  return { key:null, value:undefined };
}

// pickers
function pickCost(r){ return getFuzzy(r,[ nk => nk==='cost' || nk==='spend' || nk.endsWith('costeur') || nk==='kosten' ]); }
function pickClicks(r){ return getFuzzy(r,[ nk => nk.includes('click') || nk==='clk' || nk==='klicks' ]); }
function pickImps(r){ return getFuzzy(r,[ nk => nk.includes('impression') || nk==='imp' || nk==='einblendungen' ]); }
function pickConv(r){ return getFuzzy(r,[ nk => nk.includes('allconv') || (nk.includes('conv') && !nk.includes('value')) || nk==='conversions' ]); }
function pickConvValue(r){ return getFuzzy(r,[ nk => nk==='convvalue' || nk.includes('conversionvalue') || nk.includes('allconvvalue') || nk.includes('conv_value') || nk.includes('revenue') || nk.includes('umsatz') ]); }
function pickROAS(r){ return getFuzzy(r,[ nk => nk==='roas' || nk.includes('returnonadspend') ]); }
function pickValuePerCost(r){ return getFuzzy(r,[ nk => nk.includes('valuepercost') || nk.includes('convvaluepercost') ]); }

const normalizeChannel = (c) => {
  const x = up(c);
  if (x.includes('SEARCH')) return 'SEARCH';
  if (x.includes('PERFORMANCE') || x.includes('P-MAX') || x.includes('PMAX')) return 'PERFORMANCE MAX';
  if (x.includes('DEMAND') || x.includes('DISCOVERY') || x.includes('VIDEO') || x.includes('DISPLAY') || x.includes('YOUTUBE'))
    return 'DEMAND GEN';
  return x || 'UNKNOWN';
};

// ---------- main mapping ----------
function mapRow(r){
  const name =
    (r.name ?? r.campaign_name ?? r['Campaign'] ?? r['Kampagne'] ?? r['campaign'] ?? r.id ?? '').toString().trim() || `Unknown_${r.id ?? ''}`;
  const channel = normalizeChannel(r.channel ?? r.campaign_type ?? r['Channel'] ?? r['Netzwerk'] ?? '');

  const costK = pickCost(r), clicksK = pickClicks(r), impsK = pickImps(r);
  const convK = pickConv(r), valK = pickConvValue(r);
  const roasK = pickROAS(r), vpcK = pickValuePerCost(r);

  const cost = toNum(costK.value);
  const clk  = toNum(clicksK.value);
  const imp  = toNum(impsK.value);
  const conv = toNum(convK.value);
  let val    = toNum(valK.value);

  const roasFromCol = toNum(roasK.value);
  const roasFromVpc = toNum(vpcK.value);
  if (val === 0 && roasFromCol > 0 && cost > 0) val = roasFromCol * cost;
  else if (val === 0 && roasFromVpc > 0 && cost > 0) val = roasFromVpc * cost;

  const roas = (cost > 0 && val > 0) ? (val / cost) : 0;
  const ctr  = imp>0 ? (clk/imp) : toPct(r.ctr ?? r['CTR']);
  const cpc  = clk>0 ? (cost/clk) : toNum(r.cpc ?? r['CPC']);
  const cvr  = clk>0 ? (conv/clk) : toPct(r.cvr ?? r['CVR'] ?? r['Conv rate']);

  if (DEBUG) console.log('Mapped', name, { cost, val, conv, roas });

  return { name, channel, imp, clk, cost, conv, val, ctr, cpc, cvr, roas };
}

// ---------- group by campaign ----------
const mapped = rows.map(mapRow).filter(d => d.name && d.name.length >= MIN_NAME_LEN);
const grouped = {};
for (const r of mapped) {
  const k = r.name;
  if (!grouped[k]) grouped[k] = { ...r };
  else {
    const g = grouped[k];
    g.imp += r.imp; g.clk += r.clk; g.cost += r.cost; g.conv += r.conv; g.val += r.val;
    g.ctr = g.imp>0 ? (g.clk/g.imp) : 0;
    g.cpc = g.clk>0 ? (g.cost/g.clk) : 0;
    g.cvr = g.clk>0 ? (g.conv/g.clk) : 0;
    g.roas = g.cost>0 ? (g.val/g.cost) : 0;
  }
}
const data = Object.values(grouped);

// ---------- totals ----------
const sum = (arr,k)=>arr.reduce((a,r)=>a+(r[k]||0),0);
const totals = {
  spend: sum(data,'cost'),
  value: sum(data,'val'),
  conv:  sum(data,'conv'),
  clicks: sum(data,'clk'),
  impressions: sum(data,'imp'),
};
totals.roas = totals.spend>0 ? (totals.value/totals.spend) : 0;

// ---------- per-channel ----------
const by_channel = {};
for (const r of data) {
  const ch = r.channel || 'UNKNOWN';
  if (!by_channel[ch]) by_channel[ch] = { spend:0, value:0, conv:0, clicks:0, impressions:0 };
  const g = by_channel[ch];
  g.spend += r.cost; g.value += r.val; g.conv += r.conv; g.clicks += r.clk; g.impressions += r.imp;
}
for (const ch of Object.keys(by_channel)) {
  const g = by_channel[ch];
  g.roas = g.spend>0 ? (g.value/g.spend) : 0;
  g.ctr  = g.impressions>0 ? (g.clicks/g.impressions) : 0;
  g.cpc  = g.clicks>0 ? (g.spend/g.clicks) : 0;
}
const channel_split = {};
for (const ch of Object.keys(by_channel)) {
  channel_split[ch] = totals.spend>0 ? (by_channel[ch].spend/totals.spend) : 0;
}

// ---------- highs & lows ----------
const eligible = data.filter(r => r.cost >= MIN_SPEND_FOR_RANK).sort((a,b)=>b.roas-a.roas);
function toEntry(r){
  const cvrPct = r.clk>0 ? (r.conv/r.clk)*100 : (r.cvr*100);
  const ctrPct = r.imp>0 ? (r.clk/r.imp)*100 : (r.ctr*100);
  return {
    name:r.name,
    roas:r.roas,
    conv:r.conv,
    conv_display: fmtConv(r.conv),
    cvr_pct:cvrPct||0,
    spend:r.cost,
    clicks:r.clk,
    ctr_pct:ctrPct||0,
    cpc:r.cpc
  };
}
const topRaw = eligible.slice(0,3).map(toEntry);
const bottomRaw = eligible.length>=6 ? eligible.slice().sort((a,b)=>a.roas-b.roas).slice(0,3).map(toEntry) : [];

// formatted label
const label = e => `${e.name} (ROAS ${e.roas.toFixed(2)}, CVR ${e.cvr_pct.toFixed(2)}%, ${fmtConv(e.conv)} conv)`;

const highs_lows = {
  top3_labels: topRaw.map(label),
  bottom3_labels: bottomRaw.map(label),
  top3_raw: topRaw,
  bottom3_raw: bottomRaw
};

// ---------- output ----------
const out = {
  brand: BRAND,
  period: PERIOD,
  totals,
  by_channel,
  channel_split,
  highs_lows,
  source_rows: rows.length,
  grouped_rows: data.length
};
return [{ json: out }];

