// INPUT: rows of campaigns for last week (fields like: id,name,channel,imp,clk,cost,conv,val,ctr,cpc,cvr,roas)
// OUTPUT: one item: { brand:'MT'|'MM', period:'last_week', totals, by_channel, channel_split, highs_lows }

