const byKey = {};
for (const r of rows) {
  const ch = String(r.channel || 'OTHER').toUpperCase();
  byKey[ch] = byKey[ch] || { spend:0, clicks:0, conv:0, imp:0, value:0 };
  byKey[ch].spend  += r.cost  || 0;
  byKey[ch].clicks += r.clk   || 0;
  byKey[ch].conv   += r.conv  || 0;
  byKey[ch].imp    += r.imp   || 0;
  byKey[ch].value  += r.val   || 0;
}
const by_channel = {};
Object.entries(byKey).forEach(([ch, g]) => {
  by_channel[ch] = {
    spend:  g.spend,
    clicks: g.clicks,
    conv:   g.conv,
    roas:   safeDiv(g.value, g.spend),
    ctr:    safeDiv(g.clicks, g.imp),
    cpc:    safeDiv(g.spend, g.clicks),
  };
});

// channel split (share of spend)
const channel_split = {};
Object.entries(byKey).forEach(([ch, g]) => {
  channel_split[ch] = spend ? g.spend / spend : 0;
});

// highs & lows by ROAS (labels only)
const withRoas = rows.map(r => ({ name: r.name || String(r.id || 'Unknown'), roas: r.roas ?? safeDiv(r.val, r.cost) }));
withRoas.sort((a,b) => (b.roas||0) - (a.roas||0));
const top3_labels = withRoas.slice(0,3).map(x => x.name);
const bottom3_labels = withRoas.slice(-3).map(x => x.name);

return [{
  json: {
    brand: BRAND,
    period: PERIOD,
    totals: { spend, clicks, conv, value, roas },
    by_channel,
    channel_split,
    highs_lows: { top3_labels, bottom3_labels }
  }
}];

// MindMeister monthly: LAST month (rows 43 Summe, 44 Leftover)

const BRAND = "MindMeister";
const SUM_ROW = 43;     // Summe
const LEFT_ROW = 44;    // Leftover
const MODE = "last";    // "current" | "last"

const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const now = new Date();
const monthName = MODE === "last" ? MONTHS[(now.getMonth()+11)%12] : MONTHS[now.getMonth()];

const rows = $input.all().map(i => i.json);

function labelOf(r){
  const k = Object.keys(r).find(x => /^col[\s_]*1$/i.test(x)) || Object.keys(r)[0];
  return String(r?.[k] ?? "").trim();
}
function findRow(sumOrLeft) {
  const wanted = sumOrLeft === "sum" ? "summe" : "leftover";
  let row = rows.find(r => labelOf(r).toLowerCase() === wanted);
  if (!row) row = rows.find(r => Number(r.row_number) === (sumOrLeft === "sum" ? SUM_ROW : LEFT_ROW));
  return row;
}
function toNum(v){
  if (typeof v === "number") return v;
  if (v == null || v === "") return 0;
  const s = String(v).trim().replace(/\s/g,"").replace(/[€]/g,"").replace(/\./g,"").replace(/,/g,".").replace(/[^\d.\-]/g,"");
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}
function fmtEUR(n){
  const num = n.toLocaleString("de-DE",{minimumFractionDigits:2,maximumFractionDigits:2});
  return `€${num}`;
}

const rowSum = findRow("sum");
const rowLeft = findRow("left");

const spend = toNum(rowSum?.[monthName]);
const leftover = toNum(rowLeft?.[monthName]);
const budget = spend + leftover;
const pct = budget ? Number(((spend / budget) * 100).toFixed(1)) : 0;

return [{
  json: {
    source: BRAND,
    month_name: monthName,
    total_budget: budget,
    total_spend: spend,
    leftover,
    pct_spent: pct,
    summary_text: `Total budget: ${fmtEUR(budget)} — total spend: ${fmtEUR(spend)} (${pct}% used, ${fmtEUR(leftover)} left)`
  }
}];

// Input: exactly two items from the brand-level Merge (Append):
// { brand:'MT'|'MM', period:'last_week'|'prev_week', ... }
// Output: single item: { brand:'MT'|'MM', last:{...}, prev:{...} }

const items = $input.all().map(i => i.json);
if (items.length !== 2) {
  // Safety: if something upstream changes, fail loudly.
  throw new Error(`Expected 2 items for brand bundle, got ${items.length}`);
}

const brand = items[0]?.brand || items[1]?.brand || 'UNKNOWN';
const out = { brand, last: null, prev: null };

for (const it of items) {
  if (it.period === 'last_month') out.last = it;
  else if (it.period === 'prev_month') out.prev = it;
}

return [{ json: out }];

/***********************************************
 * Prep Monthly for Agent - MM only
 * Input: [wrap_mm_month item, budget item]
 * Output: { monthly_payload: { MM:{...}, meta } }
 ***********************************************/
const all = $input.all().map(i => i.json);
const mmBundle = all.find(i => i.brand === 'MM' && ('last' in i || 'prev' in i));
const budget   = all.find(i => i.source === 'MindMeister' || i.pct_spent !== undefined);

if (!mmBundle) throw new Error('No MM monthly bundle found in input');

const last = mmBundle.last || {};
const prev = mmBundle.prev || {};
const pct  = (n, d) => (Number.isFinite(n) && Number.isFinite(d) && d !== 0) ? (n - d) / d : null;

const mom = {
  spend:  pct(last.totals?.spend, prev.totals?.spend),
  conv:   pct(last.totals?.conv,  prev.totals?.conv),
  roas:   pct(last.totals?.roas,  prev.totals?.roas),
  ctr:    pct(last.totals?.ctr,   prev.totals?.ctr),
  cpc:    pct(last.totals?.cpc,   prev.totals?.cpc),
  clicks: pct(last.totals?.clicks,prev.totals?.clicks),
};

const MONTHS = ['January','February','March','April','May','June',
                'July','August','September','October','November','December'];
const now = new Date();
const lastMonthName = MONTHS[(now.getMonth() + 11) % 12];
const lastMonthYear = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();

return [{
  json: {
    monthly_payload: {
      MM: {
        last:        last,
        prev:        prev,
        mom:         mom,
        per_channel: last.by_channel || {},
        highs_lows:  { top3: last.top3_labels || [], bottom3: last.bottom3_labels || [] },
        budget:      budget || null,
      },
      meta: {
        generated_at_iso: new Date().toISOString(),
        month_label: `${lastMonthName} ${lastMonthYear}`,
        brand: 'MM',
        type: 'monthly',
      }
    }
  }
}];
